class Solution:
    def getGoodIndices(self, variables: List[List[int]], target: int) -> List[int]:
        result = []
        for i, (a, b, c, m) in enumerate(variables):
            # Compute (a^b % 10)^c % m
            first_part = pow(a, b, 10)
            second_part = pow(first_part, c, m)
            if second_part == target:
                result.append(i)
        return result
